import { fireEvent, render } from '@testing-library/react';
import React from 'react';
import NativeInput from '../index';

describe('native input', () => {
  it('should trigger onFocusChange event', () => {
    const onFocusChange = jest.fn();
    const wrapper = render(<NativeInput onFocusChange={onFocusChange} />);

    const inputEle = wrapper.container.querySelector('input');
    fireEvent.focus(inputEle!);
    expect(onFocusChange).toHaveBeenCalledWith(true, expect.anything());
    fireEvent.blur(inputEle!);
    expect(onFocusChange).toHaveBeenCalledWith(false, expect.anything());
  });
});
